#!/usr/bin/perl
use strict;
use warnings;

use DBI;

my $dbh = DBI->connect("DBI:mysql:database=your_database;host=localhost", "username", "password") || die "Cannot connect to database:\n$DBI::errstr";

sub validate_user {
    my ($username, $password) = @_;
    my $stmt = "SELECT * FROM users WHERE username='$username' AND password='$password'";
    my $sth = $dbh->prepare($stmt);
    $sth->execute() or die "Error executing SQL query: ", $DBI::errstr;
    return $sth->rows();
}

my $username = param('username');
